187→    }
188→    10% {
189→      opacity: 0.6;
190→    }
191→    100% {
192→      opacity: 0;
193→      transform: translateY(-200px) scale(0);
194→    }
195→  }
196→</style>
197→</head>
198→<body>
199→
200→<div class="particles" id="particles"></div>
201→
202→<div class="container">
203→  <h1>Random</h1>
204→
205→  <div class="bounds">
206→    <div class="bound-group">
207→      <label>Min</label>
208→      <input type="number" id="min" value="1">
209→    </div>
210→    <span class="separator">&ndash;</span>
211→    <div class="bound-group">
212→      <label>Max</label>
213→      <input type="number" id="max" value="4">
214→    </div>
215→  </div>
216→
217→  <div class="result-box" id="resultBox">
218→    <span class="result-text" id="result">?</span>
219→  </div>
220→
221→  <button id="generate">Generate</button>
222→</div>
223→
224→<script>
225→  const minInput = document.getElementById('min');
226→  const maxInput = document.getElementById('max');
227→  const resultBox = document.getElementById('resultBox');
228→  const resultEl = document.getElementById('result');
229→  const generateBtn = document.getElementById('generate');
230→  const particlesContainer = document.getElementById('particles');
231→
232→  // Restore bounds from localStorage
233→  const savedMin = localStorage.getItem('random-min');
234→  const savedMax = localStorage.getItem('random-max');
235→  if (savedMin !== null) minInput.value = savedMin;
236→  if (savedMax !== null) maxInput.value = savedMax;
237→
238→  // Persist bounds on change
239→  minInput.addEventListener('input', () => localStorage.setItem('random-min', minInput.value));
240→  maxInput.addEventListener('input', () => localStorage.setItem('random-max', maxInput.value));
241→
242→  function randomInRange(min, max) {
243→    return Math.floor(Math.random() * (max - min + 1)) + min;
244→  }
245→
246→  function spawnParticles() {
247→    const box = resultBox.getBoundingClientRect();
248→    const cx = box.left + box.width / 2;
249→    const cy = box.top + box.height / 2;
250→
251→    for (let i = 0; i < 16; i++) {
252→      const p = document.createElement('div');
253→      p.className = 'particle';
254→      const angle = Math.random() * Math.PI * 2;
255→      const dist = 30 + Math.random() * 60;
256→      p.style.left = (cx + Math.cos(angle) * dist) + 'px';
257→      p.style.top = cy + 'px';
258→      p.style.animation = `float-up ${0.6 + Math.random() * 0.6}s ease-out forwards`;
259→      p.style.animationDelay = Math.random() * 0.15 + 's';
260→      particlesContainer.appendChild(p);
261→      setTimeout(() => p.remove(), 1500);
262→    }
263→  }
264→
265→  function generate() {
266→    const min = parseInt(minInput.value, 10);
267→    const max = parseInt(maxInput.value, 10);
268→
269→    if (isNaN(min) || isNaN(max) || min > max) return;
270→
271→    generateBtn.disabled = true;
272→    resultBox.classList.remove('landed');
273→    resultBox.classList.add('rolling');
274→
275→    const final = randomInRange(min, max);
276→    const totalDuration = 1200;
277→    const startTime = performance.now();
278→
279→    function tick(now) {
280→      const elapsed = now - startTime;
281→      const progress = Math.min(elapsed / totalDuration, 1);
282→
283→      // Slow down: interval grows as progress increases
284→      const interval = 40 + progress * 200;
285→
286→      if (progress < 1) {
287→        resultEl.textContent = randomInRange(min, max);
288→        setTimeout(() => requestAnimationFrame(tick), interval);
289→      } else {
290→        // Land on final value
291→        resultEl.textContent = final;
292→        resultBox.classList.remove('rolling');
293→        resultBox.classList.add('landed');
294→        generateBtn.disabled = false;
295→        spawnParticles();
296→      }
297→    }
298→
299→    requestAnimationFrame(tick);
300→  }
301→
302→  generateBtn.addEventListener('click', generate);
303→
304→  // Keyboard shortcut: Enter or Space
305→  document.addEventListener('keydown', (e) => {
306→    if (e.key === 'Enter' && document.activeElement.tagName !== 'INPUT') {
307→      generate();
308→    }
309→  });
310→</script>
311→
312→</body>
313→</html>
