// Cryptographically secure random — uses OS entropy via Web Crypto API
// Uniform distribution: rejection sampling eliminates modulo bias
function randomInRange(min, max) {
  const range = max - min + 1;
  const bytesNeeded = Math.ceil(Math.log2(range) / 8) || 1;
  const maxValid = Math.floor((256 ** bytesNeeded) / range) * range;
  let value;
  do {
    const buf = new Uint8Array(bytesNeeded);
    crypto.getRandomValues(buf);
    value = 0;
    for (let i = 0; i < bytesNeeded; i++) value = value * 256 + buf[i];
  } while (value >= maxValid); // reject to avoid modulo bias
  return min + (value % range);
}

// --- Web Audio SFX ---
const audioCtx = new (window.AudioContext || window.webkitAudioContext)();

function playTick(progress) {
  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();
  osc.connect(gain);
  gain.connect(audioCtx.destination);

  // pitch rises slightly as it slows down
  osc.type = 'square';
  osc.frequency.value = 220 + progress * 300;

  const now = audioCtx.currentTime;
  gain.gain.setValueAtTime(0.06, now);
  gain.gain.exponentialRampToValueAtTime(0.001, now + 0.06);

  osc.start(now);
  osc.stop(now + 0.06);
}

function playLand() {
  const now = audioCtx.currentTime;

  // Chord: two oscillators for a triumphant chiptune hit
  const notes = [523.25, 659.25, 783.99]; // C5, E5, G5
  notes.forEach((freq, i) => {
    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();
    osc.connect(gain);
    gain.connect(audioCtx.destination);

    osc.type = 'square';
    osc.frequency.value = freq;

    const t = now + i * 0.04;
    gain.gain.setValueAtTime(0.12, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.35);

    osc.start(t);
    osc.stop(t + 0.35);
  });
}

